import{_ as e,a as t,b as o,c as d,d as n}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as r,o as l,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/ocr.md","filePath":"ms-MY/Other/ocr.md","lastUpdated":1781962217000}'),u={name:"ms-MY/Other/ocr.md"};function p(g,a,h,m,k,b){return l(),s("div",null,[...a[0]||(a[0]=[c('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR mengekstrak text daripada images, scans dan document screenshots.</p><p>Selepas recognition, anda boleh copy result, export sebagai <code>Markdown</code>, <code>PDF</code> atau <code>Word</code>, atau package beberapa formats bersama untuk download.</p><h2 id="fungsi-ocr" tabindex="-1">Fungsi OCR <a class="header-anchor" href="#fungsi-ocr" aria-label="Permalink to &quot;Fungsi OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>Mengekstrak text daripada images, screenshots dan scans.</td></tr><tr><td>Document layout recognition</td><td>Lebih baik untuk tables, formulas, stamps dan mixed text-image layouts.</td></tr><tr><td>Multiple services</td><td>Menyokong Baidu PaddleOCR, Microsoft Azure Vision dan Google Vision.</td></tr><tr><td>Copy results</td><td>Copy recognized text selepas processing.</td></tr><tr><td>Export files</td><td>Export <code>Markdown</code>, <code>PDF</code> dan <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>Selepas recognize beberapa files, download results sebagai package.</td></tr></tbody></table><h2 id="configure-ocr-services-dahulu" tabindex="-1">Configure OCR Services Dahulu <a class="header-anchor" href="#configure-ocr-services-dahulu" aria-label="Permalink to &quot;Configure OCR Services Dahulu&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP geolocation and OCR" loading="lazy"></p><p>Isi credentials untuk services yang mahu digunakan:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Recommended first choice. Baik untuk documents, images, tables dan mixed layouts.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> dan <code>Azure Vision API Key</code></td><td>Berguna jika anda sudah menggunakan Microsoft cloud services.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> hanya digunakan untuk quota query.</td><td>Berguna jika anda menggunakan Google Cloud services.</td></tr></tbody></table><p>Save selepas mengisi credentials.</p><p>Untuk initial testing, configure satu service sahaja sudah cukup. Tidak perlu ketiga-tiganya.</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup mempunyai dua bahagian:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>Menggunakan OCR</td><td>Enable <code>Cloud Vision API</code>, kemudian cipta <code>API Key</code>.</td></tr><tr><td>Query usage</td><td>Cipta service account, grant <code>Monitoring Viewer</code>, kemudian download service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="gunakan-google-untuk-ocr" tabindex="-1">Gunakan Google Untuk OCR <a class="header-anchor" href="#gunakan-google-untuk-ocr" aria-label="Permalink to &quot;Gunakan Google Untuk OCR&quot;">​</a></h3><ol><li>Buka Google Cloud Console.</li><li>Pergi ke <code>APIs &amp; Services</code>.</li><li>Buka <code>Library</code>, cari <code>Cloud Vision API</code> dan enable.</li><li>Kembali ke <code>Credentials</code>.</li><li>Cipta <code>API Key</code>.</li><li>Buka API Key dan copy.</li><li>Paste ke <code>Google Vision API Key</code> dalam ImgBed.</li><li>Save.</li></ol><p>Selepas itu, anda boleh memilih Google Vision dalam OCR dialog.</p><h3 id="query-google-usage" tabindex="-1">Query Google Usage <a class="header-anchor" href="#query-google-usage" aria-label="Permalink to &quot;Query Google Usage&quot;">​</a></h3><p>Quota query tidak required untuk recognition.</p><p>Ia hanya menunjukkan anggaran berapa banyak Google Vision calls digunakan dalam 30 hari terakhir.</p><ol><li>Dalam Google Cloud Console, buka <code>IAM &amp; Admin</code>.</li><li>Buka <code>Service Accounts</code>.</li><li>Cipta service account, contohnya <code>vision-monitor</code>.</li><li>Grant role <code>Monitoring Viewer</code>.</li><li>Buka service account details dan create key.</li><li>Pilih <code>JSON</code>.</li><li>Download generated JSON file.</li><li>Kembali ke ImgBed dan import di bawah service account <code>JSON</code> (optional).</li><li>Selepas import berjaya, klik quota query.</li></ol><p>Selepas import, ImgBed menunjukkan project name yang memiliki service account. Semasa query usage, ImgBed membaca Google monitoring data dan menunjukkan call count bulan ini.</p><p>Ringkasnya:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Melakukan OCR recognition.</td></tr><tr><td>Service account <code>JSON</code></td><td>Query berapa banyak Google Vision calls digunakan.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Membenarkan service account membaca usage data.</td></tr></tbody></table><h2 id="dapatkan-baidu-paddleocr-token" tabindex="-1">Dapatkan Baidu PaddleOCR Token <a class="header-anchor" href="#dapatkan-baidu-paddleocr-token" aria-label="Permalink to &quot;Dapatkan Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR memerlukan access token.</p><p><img src="'+t+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Buka <code>API</code> call window pada halaman Baidu PaddleOCR, klik untuk mendapatkan token, kemudian copy.</p><p>Kembali ke ImgBed, paste ke <code>PaddleOCR Token</code> dan save.</p><h2 id="mulakan-recognition" tabindex="-1">Mulakan Recognition <a class="header-anchor" href="#mulakan-recognition" aria-label="Permalink to &quot;Mulakan Recognition&quot;">​</a></h2><p>Dalam File Management, pilih image atau document screenshot dan klik <code>OCR</code>.</p><p><img src="'+o+'" alt="OCR recognition" loading="lazy"></p><p>Dalam dialog, pilih recognition service dan model.</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Recommended default. Baik untuk documents, tables, formulas, stamps dan mixed layouts.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Simple images, ordinary text dan lightweight recognition.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multilingual, complex images dan chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Document pages yang lebih kompleks dan layout recovery.</td></tr></tbody></table><p>Jika tidak pasti, mulakan dengan <code>PP-StructureV3</code>.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Gunakan apabila image rotated atau skewed.</td></tr><tr><td>Document flattening</td><td>Gunakan untuk photographed documents dengan curvature atau tilt.</td></tr><tr><td>Layout detection</td><td>Gunakan apabila mahu preserve headings, paragraphs, tables dan image structure.</td></tr><tr><td>Chart recognition</td><td>Gunakan apabila image mengandungi charts atau structures kompleks.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Menjadikan exported Markdown lebih mudah dibaca.</td></tr></tbody></table><p>Untuk regular screenshots, kekalkan options minimum. Untuk document scans, enable lebih banyak document-related options.</p><h2 id="lihat-results" tabindex="-1">Lihat Results <a class="header-anchor" href="#lihat-results" aria-label="Permalink to &quot;Lihat Results&quot;">​</a></h2><p>Selepas recognition selesai, dialog menunjukkan result.</p><p>Anda boleh copy terus atau pilih export formats.</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>Untuk document pages, exported <code>PDF</code> boleh preserve page appearance sambil mengekalkan text searchable. Ini berguna untuk archiving scans dan mencari content kemudian.</p><h2 id="memilih-export-format" tabindex="-1">Memilih Export Format <a class="header-anchor" href="#memilih-export-format" aria-label="Permalink to &quot;Memilih Export Format&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notes, documentation systems dan editing kemudian.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Preserve page appearance dan scanned document results.</td></tr><tr><td><code>Word (.docx)</code></td><td>Layout editing, text modification dan handoff kepada orang lain.</td></tr><tr><td>Export all</td><td>Menyimpan beberapa formats dan original image, sesuai untuk archives penting.</td></tr></tbody></table><p>Jika hanya perlukan text, export Markdown.</p><p>Jika perlukan page appearance, gunakan PDF atau Word.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Exported Word documents boleh dibuka dan diedit dengan office software.</p><p><img src="'+n+`" alt="Word result" loading="lazy"></p><p>Sesetengah documents mengandungi recognized images, headings dan paragraphs dalam Word output.</p><p>Recognition quality bergantung pada original image clarity, model choice dan document complexity.</p><h2 id="file-types-terbaik-untuk-ocr" tabindex="-1">File Types Terbaik Untuk OCR <a class="header-anchor" href="#file-types-terbaik-untuk-ocr" aria-label="Permalink to &quot;File Types Terbaik Untuk OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>Recognize secara terus.</td></tr><tr><td>Scans</td><td>Prefer <code>PP-StructureV3</code>.</td></tr><tr><td>Photographed documents</td><td>Enable orientation correction dan document flattening.</td></tr><tr><td>Tables, formulas, stamps</td><td>Prefer structured models.</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> biasanya cukup.</td></tr></tbody></table><p>Images yang lebih jelas dan text yang lebih lurus biasanya menghasilkan results lebih baik.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>Semak service token atau key telah disimpan.</td></tr><tr><td>Recognition slow</td><td>Complex documents dan large images mengambil masa lebih lama.</td></tr><tr><td>Table incomplete</td><td>Cuba structured model.</td></tr><tr><td>Text ada kesilapan</td><td>Blur, glare dan skew meningkatkan recognition errors. Cuba image yang lebih jelas.</td></tr><tr><td>Word output mengandungi banyak images</td><td>Structured models mungkin preserve beberapa recognized images. Ini normal.</td></tr></tbody></table><h3 id="google-quota-query-gagal" tabindex="-1">Google Quota Query Gagal <a class="header-anchor" href="#google-quota-query-gagal" aria-label="Permalink to &quot;Google Quota Query Gagal&quot;">​</a></h3><p>Semak:</p><ol><li>Service account <code>JSON</code> telah diimport.</li><li>Service account mempunyai role <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> enabled untuk project.</li></ol><p>Jika anda hanya perlukan OCR dan bukan usage query, abaikan service account JSON dan isi hanya <code>Google Vision API Key</code>.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka System Settings</span></span>
<span class="line"><span>-&gt; Buka Other Settings</span></span>
<span class="line"><span>-&gt; Isi OCR service credentials</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Kembali ke File Management</span></span>
<span class="line"><span>-&gt; Pilih file dan klik OCR</span></span>
<span class="line"><span>-&gt; Pilih model</span></span>
<span class="line"><span>-&gt; Tunggu recognition</span></span>
<span class="line"><span>-&gt; Copy results atau export Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const x=r(u,[["render",p]]);export{f as __pageData,x as default};
